import{_ as e,o as p,c as t,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"光暗双生","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/光暗双生.md","filePath":"4.资源分区/1.血统与训练/3.心智类/光暗双生.md"}'),o={name:"4.资源分区/1.血统与训练/3.心智类/光暗双生.md"};function s(d,a,i,l,h,f){return p(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"光暗双生",tabindex:"-1"},[b("光暗双生 "),r("a",{class:"header-anchor",href:"#光暗双生","aria-label":'Permalink to "光暗双生"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调016")])])],-1),n('<h1 id="光暗双生-1" tabindex="-1">光暗双生 <a class="header-anchor" href="#光暗双生-1" aria-label="Permalink to &quot;光暗双生&quot;">​</a></h1><p>光暗双生<br> [在无尽岁月之前，世界由两位强大的女神共同守护。她们一人掌控昼，一人支配夜，平衡着世界的秩序。<br> 然而，她们的关系并不和谐。光明无处不在，而黑暗则像影子般缠绕不散。虽然她们的职责是平衡光与暗，但两人之间的矛盾不断加深。<br> 终于，混沌之力从虚空中苏醒，它是远古时代遗留下来的邪恶，试图吞噬世界的秩序。两位女神明白，如果不联手，世界将被混沌吞噬，无论是光明还是黑暗都将不复存在。<br> “这是唯一一次……我不得不承认，我们需要彼此。”一位站在无尽夜空下，声音低沉而冷漠。<br> “哼，只是一次合作罢了，”另一位回应道，眉宇间仍带着不甘，但她知道这场战斗的代价。她们必须将自己化作封印，彻底驱散混沌之力。<br> 于是，一场前所未有的神之战争在宇宙的边缘爆发。昼的光辉如烈日般燃烧天地，而夜的黑暗如深渊般吞噬一切。她们的力量融合成为了封印的核心，在最后的瞬间，光与暗化为一个永恒的符文，封印了混沌的力量，也将她们永远留在了虚无之间。<br> 世界因她们的牺牲而得以延续，光与暗的平衡恢复，但代价是两位女神永远消失在了时空的尽头。<br> 然而，命运并未结束。在她们的力量消散之时，光与暗的碎片随着时间长河流动，最终汇聚在一位普通的少女身上。</p><p>————————————</p><p>异瞳的少女对着屏幕敲下了如上的文字<br> “已经是老掉牙的故事了，这种东西现在写成厕纸都没人看吧.....”<br> “这是情怀啦——你少管”]</p><p>强化这个血统后，另一沉睡的人格会在你的体内逐级苏醒。</p><p>双生血脉：D级 交替之影（Shifting Shadows）</p><p>[雨水笼罩的城市，车灯划过的霓虹在湿漉的街面上映出支离破碎的倒影。提着新买漫画的少女匆忙将这片破碎踩成混沌的模样。【似乎有些迷路了，早知道就不超近路了】，处境如此的少女却并不感慌乱。有一种感觉，不是来自外界的喧嚣，而是内心深处的某个角落。一个独属于少女心中的声音——在自己心底一直主打陪伴。<br> 这种感觉曾如此的不真切，如夜深人静时的梦境，某个躲藏在镜中的身影在悄悄窥探，而现在，似乎已经是时候了，于是，遵循内心的声音，少女散发者微光的眼睛轻轻合上。<br> 那么，在这个迷失于城市错综复杂的街巷的夜晚，当少女再次睁开双眼，一双眼眸如同将黑夜全都纳入眼底的深渊。<br> “好久不见，现在是我的场合了，交给我吧”<br> 那是她慵懒的声音第一次响起，似乎不知沉睡了多久。]</p><p>能量池：魔力（关键属性为感知+智力）<br> 【昼夜交错（Day-Night Confluence）】<br> 少女本能地感觉到身体里两股截然不同的力量若隐若现。白天时，一股温暖的光芒在体内跳动，仿佛来自天使的扶护，赋予你比以往更强的恢复能力；夜幕降临时，冷冽的黑暗如影随形，悄悄浸入每一寸肌肤，带来如猎豹般的敏捷和夜视的本能。这种昼夜的力量虽还在沉睡，但依然能感受到它们正在逐渐醒来。<br> 白天时，你的形态固定为昼形态，这个状态下，你每小时都能进行一次魔力能量池关键属性检定，恢复成功数点魔力。<br> 夜间时，则自动切换为夜形态，此状态获得黑暗视觉与2点敏捷检定加值。</p><p>【镜中低语（Whispers of the Mirror）】<br> 现在的她不时会听到另一人格镜中的低语，这种低语如同在黑暗中徘徊的寒风，使你在受到攻击时，仿佛提前预感到危险，从而迅速做出闪避。少女明白，镜中自己的存在将日益真实，直到她彻底醒来。<br> 每轮一次，在受到攻击时，你的防御上获得感知附加成功点的闪避防御，但每次触发该能力时，将消耗一点魔力。</p><p>双生血脉：C级 光影呼唤（Call of Light and Shadow）</p><p>[最初的微弱感知逐渐变得有规律。少女越来越清晰地意识到，自己与另一个“她”在一起是命运无形的连接。那个声音随时会在她最需要的时候浮现，仿佛水到渠成般，随时可以将控制权交付给对方，少女明白何时该放手让另一个自己行动——前提是对方没有在摸鱼。<br> “我们本来就是彼此嘛，所以，这并不是什么可耻的事情”<br> 夜晚，她独自站在城市老旧楼顶，凝望着被晚霞染红的天际。她感受到那个存在与自己共鸣，仿佛两者的界限已经不再重要，呼吸与心跳都是彼此的节奏。<br> “要不是一个节奏就算心律不齐了吧”其中的某位少女如是评价。]</p><p>【昼夜交错（Day-Night Confluence）】<br> 随着双重人格开始显现，少女已经能够感知到体内力量的更深层次。在光明形态下，双手仿佛能够触碰到生命的本质，治愈力逐步增强。而在夜晚的黑影中，另一面的影子则能在背后逐渐凝聚成双翼，让其无声地掠过夜空。这种形态转换需要消耗体内的力量，但这短暂的平衡使其变得无比强大。<br> 你的外貌增加5点。昼形态获得2点快速医疗（医疗点12）。夜形态可以使用一个移动动作并消耗4点魔力，获得速度为基础移速+10的飞行能力，机动性普通，你每维持一轮该能力，就需要支付额外支付4点魔力。现在你可以主动唤醒另一人格，每回合开始时可消耗一点魔力，使用自由动作切换形态。战斗中另一形态只能存在3回合，战斗外则为15分钟，之后需要重新切换。</p><p>【暗夜冷言（Night&#39;s Cold Words）】<br> 她的冰冷言辞如刺骨寒风。她的低语如同无情的刀锋，划开敌人的内心防线，让他们在其面前变得脆弱不堪。她的语言就像一把无形的匕首，击碎他们的信念，让他们在黑夜的阴影中迷失。<br> 结合在一次近战攻击中使用，消耗3点魔力，攻击命中后，对目标释放“暗夜冷言”，使其攻击检定和闪避防御在接下来的战斗中各降低2点。每个目标只能受到一次此效果，攻击多个目标时需选择一个生效。这是一个C级心灵来源的能力。</p><p>双生血脉：B级 昼夜双生（Duality of Day and Night）</p><p>[少女与另一个自己已经不再仅仅是默契配合，而是两者真正开始合二为一。控制的权力在二者之间无缝切换，再也无需分清谁在主导，谁在追随。所有的行为与决策都如行云流水，自然而然地由两人共同完成。<br> “《环太平洋》里的机甲驾驶也不过如此嘛，嗯嗯”<br> 过去那些年所有与第二人格的共处时光，已经完全融入她的记忆中，成为一体。过去与未来，全部重叠在一起，模糊了边界。她们的记忆相互交织，分不清是属于谁的回忆。她并不感到迷失，反而更加完整。两人的存在已然超越了孤立的个体，成就了某种更为强大的整体。<br> “所以禁止再在夜里通宵看恐怖片......烂片更不行——”]</p><p>【昼夜交错（Day-Night Confluence）】<br> 昼夜的力量在她的体内彻底觉醒，两位少女的力量交织在了一起，这使她们可以根据需要随时显现出不同的人格。光明时，可以如天使般散发治愈的圣光；黑暗时，又如幽灵一般无声无息地游走在敌人背后。人格的显现不再受到昼夜的束缚，可以完全掌控了两者的力量。<br> 你可以自由转换形态，不再受到时间和魔力限制。<br> 此外，每回合一次，你可以将敏捷作为施法骰的主属性进行一次施法。<br> 昼形态在之前的基础上，当你在影片主线的抉择中做出善意的选择，在该场结束后会获得额外1点快速医疗（12医疗点） 当你施放治疗相关技能时，可以暂时失去昼形态的快速医疗，昼形态的快速医疗点数可以临时加入技能中，生效于所有目标，同时可选择让该技能优先消耗自身的这些医疗点。这持续至该技能效果结束，你可以选择提前以自由动作收回这些快速医疗，使它们失效。之后在你下个回合结束后，这些快速医疗与医疗点会重新对你生效。<br> 夜形态在之前的基础上，当你在影片中参与过击杀目标，你在该场结束后会在敏捷上获得3dp内在加值。</p><p>【裂隙之眼（Eyes of the Rift）】<br> 觉醒后的少女，双眼透射出无尽的力量。左眼象征光明的瞳孔中闪烁着柔和的光芒，另一只漆黑的眼眸则如无底的深渊，能直击灵魂。当用这双眼睛凝视敌人时，仿佛能够看穿他们心灵的每一道裂隙，将他们的弱点暴露在她面前。<br> 自由动作启用该能力。你的攻击检定获得【8加骰】。<br> 并且此时，在白昼形态下，你获得2点破魔；在黑夜形态下，你获得2点破甲</p><p>双生血脉：A级 昼夜共鸣（Resonance of Dusk and Dawn）</p><p>[此刻，她们已经彻底融为一体。没有了界限，也没有了区别。另一个自己不仅仅是存在于内心的声音，而是与自己灵魂的深度交织。两个人格已经无法分离，她们共同分享着记忆、感知与情感，行动不再需要分割的控制，因为她们已是同一个体。<br> “但是下周的《光明女神与黑暗女神的秘密之双生少女》的漫画周边依然要买双版本哦？”<br> 她走在城市的街道上，平静而从容，仿佛一切尽在掌握。世界对她而言，像是一本展开的书，每一页都无比清晰。她可以感知到周围的一切，轻轻松松地穿梭在人群中。尽管她表面看上去与常人无异，内心却交织着两个人的智慧与力量。<br> “啊不过即使是这样，高数题还是解不出来的，两个人也不行！”<br> “现在是考虑这个的时候吗，快拿出你的力量战斗啊啊啊啊啊啊——”]</p><p>【命运共鸣（Resonance of Fate）】<br> 命运的丝线在二人之间紧紧缠绕。两人的存在感在这个世界中愈发强烈，命运的力量不再能够将其支配。无论是预言还是操纵，所有针对她的命运攻击都会被这份共鸣之力击碎。在这命运的战场上，已是不可战胜的存在。<br> 你现在免疫A级命运效果</p><p>【昼夜交替的意志（Will of Dusk and Dawn）】<br> 当光明与黑暗的力量完美交融，两种人格的存在达到了一种奇妙的平衡。以将灵魂与力量彻底交融重构，能够进入一种全新的状态，昼夜的力量同时在少女体内沸腾，让其拥有前所未有的力量。但这种形态过于强大，无法长时间维持，并会在战斗后陷入虚弱。</p><p>每天一次，标准动作消耗14点魔力与2点意志进入“昼夜交替”状态，持续一场景，立刻获得不可豁免10点精神束缚点数。<br> 该形态下你获得以下效果：<br> A级时空与心灵免疫。<br> 你的攻击检定获得【传奇】特性。<br> 最后，在这个状态下，每场影片一次，你能够以自由动作释放一次【昼夜之歌】。</p><p>【昼夜之歌（Song of Day and Night）】<br> 光与暗，昼与夜的声音在空气中交织成古老的歌声，仿佛在唱述一个远古的传说。她们的歌声充满了命运的力量，能够唤醒沉睡的灵魂，甚至将逝去的生命重新带回人世。这是属于命运的旋律，能改变生与死的界限。<br> 每影片一次，你可以用标准动作选择智力*1米内一个死亡的队友，使其立刻复活，这是一个S级命运来源的复活效果。</p><p>【镜中审判（Judgment of the Mirror）】<br> 少女们曾通过命运的镜子窥探敌人的命运线，并用她们的力量切断它。敌人在她们的注视下失去命运的庇佑，变得极为脆弱。这份审判无情且难以违抗，使敌人在战斗中失去预知与命运的助力。<br> 选择70米内一个目标，以标准动作进行一次攻击检定，若该次攻击造成伤害便可以额外消耗6点魔力，使其进行一次强韧豁免，若失败则一场景内所有检定获得【劣化2】，这是一个A级命运来源的能力。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',26)])])}const g=e(o,[["render",s]]);export{_ as __pageData,g as default};
